import React, { useRef, useState, useCallback } from 'react'
import ChatContentMuted from '../chat/ChatContentMuted'
import ChatContentMessages from '../chat-messages/ChatContentMessages'
import useChatLog from '../hooks/useChatLog'
import useThreadPagination from '../hooks/useThreadPagination'

export default function ChatThreadContent({ thread, parentMessage, parentChannel }) {
  const { log } = useChatLog({ component: '[ChatThreadContent]' })
  const virtuosoRef = useRef(null)
  const [topVisibleMessageId, setTopVisibleMessageId] = useState('')

  const parentMessageId = parentMessage?.id
  const totalReplies = parentMessage?.reply_count ?? 0
  const initialReplies = thread?.state?.getLatestValue?.()?.replies || []
  const { replies, loading, firstItemIndex, prependItems, appendItems } = useThreadPagination({
    thread,
    parentChannel,
    parentMessageId,
    totalReplies,
    initialReplies,
  })

  const contentMessages = parentMessage ? [parentMessage, ...(replies || [])] : replies || []

  const isMuted = !!parentChannel?.muteStatus()?.muted

  // Mark thread as read as the visible range changes
  const markThreadReadOnRangeChange = useCallback(() => {
    try {
      thread?.markAsRead()
    } catch (e) {
      log('Error marking thread as read', e)
    }
  }, [thread, log])

  return (
    <>
      {(contentMessages?.length > 0 || loading) && (
        <ChatContentMessages
          channel={parentChannel}
          messages={contentMessages}
          unreadMessages={[]}
          firstItemIndex={firstItemIndex}
          prependItems={prependItems}
          appendItems={appendItems}
          virtuosoRef={virtuosoRef}
          loading={loading}
          hideReplyButtons
          markChannelReadOnRangeChange={markThreadReadOnRangeChange}
          setTopVisibleMessageId={setTopVisibleMessageId}
          topVisibleMessageId={topVisibleMessageId}
          isThread
        />
      )}
      {isMuted && <ChatContentMuted channel={parentChannel} />}
    </>
  )
}
