import { useEffect, useState } from 'react'
import { i18n } from '@fs/zion-locale'

export default function useChatTyping({ channel, myUserId, showTyping, isThread }) {
  const [typingLabel, setTypingLabel] = useState(null)

  // see: https://getstream.io/chat/docs/javascript/typing_indicators/?language=javascript
  useEffect(() => {
    let typingStartEventListener = null
    let typingStopEventListener = null

    if (channel && showTyping) {
      // start typing event handling
      typingStartEventListener = channel.on('typing.start', (e) => {
        const name = e.user.name
        if (e.user.id !== myUserId) {
          if (isThread) {
            setTypingLabel(
              i18n.t('chat.person-is-typing-in-thread.message', `{name} is typing in a thread...`, { name })
            )
          } else {
            setTypingLabel(i18n.t('chat.person-is-typing.message', `{name} is typing...`, { name }))
          }
        }
      })

      // stop typing event handling
      typingStopEventListener = channel.on('typing.stop', () => {
        setTypingLabel(null)
      })
    }
    return () => {
      // Ensure typing label is cleared when switching channels (FSCHAT-505)
      setTypingLabel(null)
      if (typingStartEventListener) {
        typingStartEventListener.unsubscribe()
      }
      if (typingStopEventListener) {
        typingStopEventListener.unsubscribe()
      }
    }
  }, [showTyping, channel, myUserId, isThread])

  return typingLabel
}
