import { useCallback, useEffect, useRef, useState } from 'react'
import { THREAD_PAGE_SIZE } from '../services/fsChat/fsChannelEnums'
import useChatLog from './useChatLog'

const compareByCreatedAt = (a, b) => new Date(a?.created_at) - new Date(b?.created_at)
const dedupeById = (list) => {
  const seen = new Set()
  return (list || []).filter((m) => {
    const id = m?.id
    if (!id || seen.has(id)) return false
    seen.add(id)
    return true
  })
}
const mergeReplies = (prev = [], next = []) => {
  const merged = dedupeById([...(next || []), ...(prev || [])])
  merged.sort(compareByCreatedAt)
  return merged
}

export default function useThreadPagination({
  thread,
  parentChannel,
  parentMessageId,
  totalReplies = 0,
  initialReplies = [],
} = {}) {
  const { log } = useChatLog({ component: '[useThreadPagination]' })

  const [replies, setReplies] = useState(() => [...(initialReplies || [])].sort(compareByCreatedAt))
  const [hasMoreDown, setHasMoreDown] = useState(true)
  const [loading, setLoading] = useState(false)
  const loadingRef = useRef(false)
  const [firstItemIndex, setFirstItemIndex] = useState(0)
  const [reachedOldest, setReachedOldest] = useState(false)

  const hasMoreUp = !reachedOldest && (replies?.length || 0) < (totalReplies || 0)

  // subscribe to thread state
  useEffect(() => {
    if (!thread?.state) return () => {}
    const unsubscribe = thread.state.subscribe((newState) => {
      const incoming = newState?.replies || []
      if (incoming?.length) {
        setReplies((prev) => mergeReplies(prev, incoming))
      }
    })
    // get access to events and handlers
    thread.registerSubscriptions?.()
    return () => {
      setReplies([])
      unsubscribe && unsubscribe()
    }
  }, [thread])

  const prependItems = useCallback(async () => {
    if (loading || !hasMoreUp) return
    if (!parentChannel || !parentMessageId) return
    const firstReply = replies?.[0]
    if (!firstReply) return
    setLoading(true)
    try {
      const page = await parentChannel.getReplies(parentMessageId, { limit: THREAD_PAGE_SIZE, id_lte: firstReply.id })
      const pageReplies = page?.messages || []
      const cleaned = pageReplies.filter((m) => m?.id && m.id !== firstReply.id)
      if (cleaned.length === 0) {
        setReachedOldest(true)
        return
      }
      setReplies((prev) => mergeReplies(prev, cleaned))
      setFirstItemIndex((i) => i + cleaned.length)
      if (pageReplies.length < THREAD_PAGE_SIZE) setReachedOldest(true)
    } catch (e) {
      log('Error fetching older thread replies', e)
    } finally {
      setLoading(false)
    }
  }, [loading, hasMoreUp, parentChannel, parentMessageId, replies, log])

  const appendItems = useCallback(async () => {
    if (loadingRef.current || !hasMoreDown) return
    if (!parentChannel || !parentMessageId) return
    const lastReply = replies?.at(-1)
    if (!lastReply) return
    loadingRef.current = true
    setLoading(true)
    try {
      const page = await parentChannel.getReplies(parentMessageId, { limit: THREAD_PAGE_SIZE, id_gt: lastReply.id }, [
        { created_at: 1 },
      ])
      const pageReplies = page?.messages || []
      if (!pageReplies?.length) {
        setHasMoreDown(false)
        return
      }
      setReplies((prev) => mergeReplies(prev, pageReplies))
      if (pageReplies.length < THREAD_PAGE_SIZE) setHasMoreDown(false)
    } catch (e) {
      log('Error fetching newer thread replies', e)
    } finally {
      loadingRef.current = false
      setLoading(false)
    }
  }, [hasMoreDown, parentChannel, parentMessageId, replies, log])

  return {
    replies,
    hasMoreUp,
    hasMoreDown,
    loading,
    firstItemIndex,
    prependItems,
    appendItems,
  }
}
