import { Row, Button, useOverlay, Ellipsis } from '@fs/zion-ui'
import React from 'react'
import { ContactOverlay } from '@fs/zion-contact-overlay'
import { useTranslation } from 'react-i18next'
import { css } from '@linaria/core'
import { chatAvatar } from '../chat-avatar/chatAvatar'
import { getPortraitUrlFromCisId } from '../helpers/portraitServiceHelper'
import { cisIdFromChatUserId } from '../helpers/stream/streamChatHelper'

const captionCss = css`
  font-size: 12px;
`

export default function ChatHeaderPersonBlock({ parentMessage, repliesMessage, member, name }) {
  const [t] = useTranslation()
  const contactOverlay = useOverlay()
  const isOnline = member?.user?.online
  const cisId = member ? cisIdFromChatUserId(member?.user?.id) : null
  const portraitUrl = getPortraitUrlFromCisId(cisId)
  const description = parentMessage ? `${t('chat.thread.label', 'Thread')} | ${name}` : name

  return (
    <Row alignY="middle" gutters="xxs">
      <div noShrinkX>{chatAvatar({ name, src: portraitUrl, isOnline, noShrinkX: true, size: 'xs' })}</div>
      <div growX>
        {!description && t('common-ui:loading.ellipsis.label', 'Loading...')}
        <Button onClick={contactOverlay.handleClick}>{description}</Button>
      </div>
      <Ellipsis alignY="middle" className={captionCss}>
        {parentMessage && repliesMessage}
      </Ellipsis>
      <ContactOverlay portraitUrl={portraitUrl} contact={{ cisId }} overlay={contactOverlay} hideMessaging />
    </Row>
  )
}
