import { Row, MarginBox } from '@fs/zion-ui'
import React from 'react'
import { useChatState } from '../providers/ChatStateProvider'
import { useCurrentChannel } from '../hooks/channelHooks'
import useChatHeaderBlockInfo from '../hooks/useChatHeaderBlockInfo'
import ChatHeaderBlock from '../chat-header/ChatHeaderBlock'
import BackButton from '../chat-buttons/BackButton'

export default function ChatThreadHeader({ parentMessage }) {
  const { connectError, client, isEmbedded } = useChatState()
  const channel = useCurrentChannel()

  const { displayPersonHeader, displayGroupHeader } = useChatHeaderBlockInfo(channel, client?.userID)

  if (connectError) return null

  return (
    <MarginBox marginX="xxs" marginY={isEmbedded ? 'nano' : 'xxs'}>
      <Row gutters="nano">
        <BackButton data-testid="close-thread-button" noShrinkX />
        <ChatHeaderBlock
          growX
          alignY="middle"
          displayPersonHeader={displayPersonHeader}
          displayGroupHeader={displayGroupHeader}
          channel={channel}
          parentMessage={parentMessage}
          isThread
        />
      </Row>
    </MarginBox>
  )
}
