import React, { useRef, useEffect, useState } from 'react'
import { useLocation, useParams, useHistory } from '@fs/zion-router'
import { css } from '@linaria/core'
import { colors, useTheme, MarginBox, LayoutBand, Row } from '@fs/zion-ui'
import { ShadowScroller } from '@fs/zion-ui/quarks-authorized-use-only'
import { VisuallyHidden } from '@reach/visually-hidden'
import { useTranslation } from 'react-i18next'
import ChatContent from './ChatContent'
import ChatThreadContent from '../chat-threads/ChatThreadContent'
import { useChatDispatch, useChatState } from '../providers/ChatStateProvider'
import useChatTyping from '../hooks/useChatTyping'
import isTouchScreen from '../helpers/isTouchScreen'
import { getChannelName } from '../helpers/stream/streamChatHelper'
import ChatThreadHeader from '../chat-threads/ChatThreadHeader'
import {
  createFsThreadChannel,
  showJoinLeaveTypingForChannel,
  isPubliclyViewableChannel,
} from '../services/fsChat/fsChatService'
import { LOG_LEVEL } from '../global/chatLog'
import { CHAT_ACTIONS } from '../hooks/useChatReducer'
import useHandleChatErrors from '../hooks/useHandleChatErrors'
import { FS_THREAD_MESSAGE_PREFIX, THREAD_PAGE_SIZE } from '../services/fsChat/fsChannelEnums'
import useChatLog from '../hooks/useChatLog'
import useChatFlags from '../hooks/useChatFlags'
import { addOrRemoveChannelMembers, useFindExistingChannel, useSyncStaleChannels } from '../hooks/channelHooks'
import { buildChatRoute, CHAT_ROUTE_KEY } from '../chat-memory-router/ChatMemoryRouter'
import { ChatAttachmentDropContainer } from '../chat-attachments/ChatAttachmentDropContainer'
import LoadingSpinner from '../chat-window/LoadingSpinner'
import ChatActionsHolder from '../chat-actions/ChatActionsHolder'
import ChatMessageAnnouncer from './ChatMessageAnnouncer'

const chatCss = css`
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  flex-shrink: 1;
  flex-grow: 1;
  overflow: hidden;
`

/**
 * Send the reply message to a separate 'fs-thread' channel.
 * This allows FSChat to get unread counts and other stream channel features missing from threads.
 */
async function sendReplyToThreadChannel({
  client,
  channels,
  parentChannelCid,
  parentMessageId,
  text,
  attachments,
  log,
  track,
}) {
  try {
    // Open the thread channel if it exists
    let threadChannel = channels.find((c) => c.id === parentMessageId)

    if (!threadChannel || !threadChannel.state?.membership?.user) {
      threadChannel = await createFsThreadChannel({ parentChannelCid, parentMessageId, client })
    }

    if (threadChannel) {
      track({ link_name: `Chat:Send Message:Reply ${threadChannel?.type}` }, { chatChannelId: threadChannel?.cid })
      const threadMessage = await threadChannel.sendMessage({ text, attachments })
      return threadMessage
    }
  } catch (e) {
    log({ msg: `Error sending reply message to fs-thread channel: error: ${e}`, level: LOG_LEVEL.ERROR })
    throw Error(e)
  }
  return undefined
}

export default function Chat({ isThread, isNarrow }) {
  const { cid, pid } = useParams()
  const { channels, client, isEmbedded, restrictToManagedGroups, parentMessage } = useChatState()
  const chatDispatch = useChatDispatch()
  const history = useHistory()
  const { log, track } = useChatLog({ component: '[Chat]' })
  const { handleBasicError, handleUserRestrictedError } = useHandleChatErrors({ log })
  const { channel, loadingChannel } = useFindExistingChannel(cid)

  useEffect(() => {
    if (!channel && !loadingChannel) {
      handleBasicError(new Error(`Channel not found for cid: ${cid}`))
      history.push(buildChatRoute(CHAT_ROUTE_KEY.CHATS))
    } else if (!isEmbedded && !loadingChannel && restrictToManagedGroups && !['fs_managed'].includes(channel?.type)) {
      handleUserRestrictedError(new Error(`User unable to access channel with cid: ${cid}`))
      history.push(buildChatRoute(CHAT_ROUTE_KEY.CHATS))
    }
  }, [
    channel,
    loadingChannel,
    cid,
    handleBasicError,
    handleUserRestrictedError,
    history,
    isEmbedded,
    restrictToManagedGroups,
  ])

  const { key } = useSyncStaleChannels({ channel })
  const userId = client?.userID
  const chatFlags = useChatFlags()
  const showTyping = showJoinLeaveTypingForChannel({ channel, chatFlags })
  const [thread, setThread] = useState()
  const typingLabel = useChatTyping({ channel, myUserId: userId, showTyping, isThread })
  const recipientLabel = getChannelName({ channel, excludeUserId: userId })
  const [t] = useTranslation()
  const location = useLocation()
  const [isSending, setIsSending] = useState(false)
  const [showSpinner, setShowSpinner] = useState(false)

  useEffect(() => {
    let isUnmounted = false
    const getParentMessageAndThreadChannel = async () => {
      try {
        // get parent message
        const { message } = await client.getMessage(pid)
        if (isUnmounted) return

        // get/set thread
        if (message?.reply_count > 0) {
          const threadResult = await client.getThread(pid, { watch: true, reply_limit: THREAD_PAGE_SIZE })
          if (isUnmounted) return
          setThread(threadResult)
        } else {
          setThread(null)
        }

        // set parent message
        chatDispatch({
          type: CHAT_ACTIONS.NEW_PARENT_MESSAGE,
          parentMessage: message,
        })
      } catch (err) {
        if (!isUnmounted) {
          handleBasicError(err, { moreInfo: 'Failed to get parent message' })
        }
      }
    }

    if (isThread && pid && client) {
      getParentMessageAndThreadChannel()
    }

    if (!pid) {
      chatDispatch({ type: CHAT_ACTIONS.NEW_PARENT_MESSAGE, parentMessage: null })
    }
    return () => {
      isUnmounted = true
      setThread(null)
    }
  }, [isThread, pid, client, chatDispatch, handleBasicError])

  const handleSendMessage = async (text, attachments) => {
    const isMember = Boolean(channel?.state?.membership?.user)
    if (isPubliclyViewableChannel(channel) && !isMember) {
      await addOrRemoveChannelMembers({ cid: channel.cid, cisIdsToAdd: [client?.user?.fs_cis_id], log })
    }
    track({ link_name: `Chat:Send Message:${channel?.type}` }, { chatChannelId: channel?.cid })
    await channel.sendMessage({ text, attachments })
    if (showJoinLeaveTypingForChannel({ channel, chatFlags })) {
      channel.stopTyping().catch((err) => log({ msg: `Error sending stopTyping event ${err}` }))
    }
  }

  // Consider Removing this code if/when stream-chat code adds unread count features to threads
  const handleReplyMessage = async (message, attachments) => {
    const text = message

    // Priority #1 Send reply to fs-thread channel for unread counts and other channel features
    const replyMessage = await sendReplyToThreadChannel({
      client,
      channels,
      chatDispatch,
      parentChannelCid: channel.cid,
      parentMessageId: pid,
      handleBasicError,
      text: message,
      attachments,
      log,
      track,
    })
    const isMember = Boolean(channel?.state?.membership?.user)
    if (isPubliclyViewableChannel(channel) && !isMember) {
      await addOrRemoveChannelMembers({ cid: channel.cid, cisIdsToAdd: [client?.user?.fs_cis_id], log })
    }
    track({ link_name: `Chat:Send Message:Duplicate Thread Reply ${channel?.type}` }, { chatChannelId: channel?.cid })

    // Priority #2 Reply in the standard stream-chat thread to add reply_count and participants to parent message
    await channel.sendMessage({
      id: `${FS_THREAD_MESSAGE_PREFIX}${replyMessage?.message?.id}`,
      text,
      attachments,
      parent_id: pid,
    })
    const threadResult = await client.getThread(pid, { watch: true, reply_limit: THREAD_PAGE_SIZE })
    setThread(threadResult)

    if (showJoinLeaveTypingForChannel({ channel, chatFlags })) {
      channel.stopTyping().catch((err) => log({ msg: `Error sending stopTyping event ${err}` }))
    }
  }

  const onSend = async (text, attachments) => {
    let timeout
    try {
      const receiverCisIds = channel.state?.members
        ? Object.keys(channel.state.members)
            .map((member) => member)
            .slice(0, 5)
            .join(', ')
        : ''
      const logData = {
        senderCisId: userId,
        channelId: cid,
        receiverCisIds,
        messageLength: text.length,
        messageText: text.length <= 15 ? text : text.slice(0, 15),
      }
      log({ msg: `Chat message sent.`, level: LOG_LEVEL.INFO }, logData)
      setIsSending(true)
      timeout = setTimeout(() => {
        setShowSpinner(true)
      }, 750)
      const threadAttachments = attachments?.filter((attachment) => attachment?.isReply)
      const nonThreadAttachments = attachments?.filter((attachment) => !attachment?.isReply)
      await (isThread ? handleReplyMessage(text, threadAttachments) : handleSendMessage(text, nonThreadAttachments))
    } catch (err) {
      handleBasicError(err, {
        moreInfo: `Failed to send chat message. ChannelId: ${channel?.cid}`,
        displayMessage: t('chat.error-sending.message', 'Failed to send the message'),
      })
      // rethrow error so the draft doesn't get deleted if there is a failure
      throw err
    } finally {
      setIsSending(false)
      setShowSpinner(false)
      clearTimeout(timeout)
    }
  }

  const focusRef = useRef()
  useEffect(() => {
    if (!isTouchScreen) {
      // automatically focus the message input. Timeout is necessary to prevent the Autosuggest from re-stealing focus.
      const current = focusRef?.current
      setTimeout(() => current?.focus(), 0)
      return () => {
        current?.blur()
      }
    }
    return undefined
    // including location in the dependency array because we want to refocus the input when the channel list item on the left is clicked, for a better experience with screen readers
  }, [cid, pid, isThread, location])

  useEffect(() => {
    chatDispatch({ type: CHAT_ACTIONS.SET_CURRENT_CID, currentCid: cid })
    return () => {
      chatDispatch({ type: CHAT_ACTIONS.SET_CURRENT_CID, currentCid: undefined })
    }
  }, [cid, chatDispatch])

  const theme = useTheme()
  const scrollerStyle = isThread
    ? { backgroundColor: theme === 'day' ? colors.transparent.blue02 : colors.transparent.blue05 }
    : {}

  scrollerStyle.minHeight = 100

  // used to pass the onFocus event, from clicking anywhere on the right panel, to ChatContent
  const focusWrapperRef = useRef()

  if (channel?.disconnected) {
    return (
      <LayoutBand alignY="middle">
        <MarginBox marginX="xs">
          <Row alignX="center" alignY="bottom" gutters="xxs" wrap>
            <LoadingSpinner />
          </Row>
        </MarginBox>
      </LayoutBand>
    )
  }

  return (
    <ChatAttachmentDropContainer isReply={isThread}>
      <ChatMessageAnnouncer />
      <div ref={focusWrapperRef} className={chatCss}>
        {isThread && !isNarrow && <ChatThreadHeader parentMessage={parentMessage} />}
        <ShadowScroller style={scrollerStyle}>
          {isThread && (
            <ChatThreadContent parentMessage={parentMessage} thread={thread} key={pid} parentChannel={channel} />
          )}
          {!isThread && (
            <>
              <VisuallyHidden as="h3">
                {t('chat.messages-from.label', 'Messages from {name}', {
                  name: recipientLabel,
                })}
              </VisuallyHidden>
              <ChatContent isTyping={!!typingLabel} channel={channel} key={key} focusWrapperRef={focusWrapperRef} />
            </>
          )}
        </ShadowScroller>
        <ChatActionsHolder
          isReply={isThread}
          messageRef={focusRef}
          onSend={onSend}
          recipientLabel={recipientLabel}
          typingLabel={typingLabel}
          isSending={isSending}
          showSpinner={showSpinner}
          isThread={isThread}
          thread={thread}
        />
      </div>
    </ChatAttachmentDropContainer>
  )
}
