import React from 'react'
import ChatHeaderPersonBlock from './ChatHeaderPersonBlock'
import { getChannelDescription, getChannelMembers, getChannelName } from '../helpers/stream/streamChatHelper'
import ChatHeaderGroupBlock from './ChatHeaderGroupBlock'
import { useChatState } from '../providers/ChatStateProvider'

export default function ChatHeaderBlock({ displayPersonHeader, displayGroupHeader, channel, parentMessage, isThread }) {
  const { client } = useChatState()
  const myUserId = client?.userID
  const members = getChannelMembers({ channel, excludeUserId: myUserId })
  return (
    <>
      {displayPersonHeader && (
        <ChatHeaderPersonBlock
          parentMessage={parentMessage}
          member={members[0]}
          name={getChannelName({ channel, excludeUserId: myUserId })}
        />
      )}
      {displayGroupHeader && (
        <ChatHeaderGroupBlock
          channel={channel}
          parentMessage={parentMessage}
          name={getChannelName({ channel, excludeUserId: myUserId })}
          description={getChannelDescription(channel)}
          growX
          isThread={isThread}
        />
      )}
    </>
  )
}
