import React from 'react'
import { VisuallyHidden } from '@reach/visually-hidden'
import { useParams } from '@fs/zion-router'
import { useChatState } from '../providers/ChatStateProvider'

export default function ChatMessageAnnouncer() {
  const { announcement } = useChatState()
  const { cid } = useParams()

  if (!announcement?.text) return null
  if (cid !== announcement.cid) return null

  return (
    <div aria-live="polite" data-testid="chat-announcer">
      <VisuallyHidden>{announcement.text}</VisuallyHidden>
    </div>
  )
}
