import { Row, Ellipsis, Avatar, colors, H6, Subheading } from '@fs/zion-ui'
import React from 'react'
import { css } from '@linaria/core'
import { HelpAskQuestion, LogoFamilysearch, LogoRootstech, PersonGroup, ThingPresentation } from '@fs/zion-icon'
import { useTranslation } from 'react-i18next'
import { getStreamChannelAvatar } from '../chat-avatar/chatAvatar'
import { getChannelDescription } from '../helpers/stream/streamChatHelper'
import {
  isPublicChannel,
  isVendorChannel,
  isSessionChannel,
  isRootsTechChannel,
  isSupportChannel,
  isDirectChannel,
  isHelperConnectChannel,
} from '../services/fsChat/fsChatService'
import { useChatState } from '../providers/ChatStateProvider'

const captionCss = css`
  margin-top: -2px;
  margin-bottom: -7px;
  font-size: 12px;
  line-height: 18px;
`

function ChatHeaderGroupBlock({ channel, parentMessage, name, description, isThread }) {
  const [t] = useTranslation()
  const { client } = useChatState()
  const loadingText = t('common-ui:loading.ellipsis.label', 'Loading...')
  const primaryText = parentMessage
    ? `${t('chat.thread.label', 'Thread')} | ${name || loadingText}`
    : name || loadingText

  const secondaryText = getChannelDescription(channel)
  const image = channel?.data?.image

  return (
    <Row gutters="xxs" guttersY="none" alignItemsY="middle">
      <div noShrinkX>
        {isPublicChannel(channel) && !image && <PersonGroup />}
        {isPublicChannel(channel) && image && <Avatar src={image} />}
        {isVendorChannel(channel) && description && <Avatar src={description} />}
        {isSessionChannel(channel) && <ThingPresentation />}
        {isRootsTechChannel(channel) && <LogoRootstech />}
        {isSupportChannel(channel) && <HelpAskQuestion color={colors.blue30} />}
        {isDirectChannel(channel) && getStreamChannelAvatar({ channel, excludeUserId: client?.userID })}
        {isHelperConnectChannel(channel) && <LogoFamilysearch background={colors.green20} size="xs" />}
      </div>
      <H6>
        <Ellipsis>{primaryText}</Ellipsis>
        <Subheading>
          {!isThread && secondaryText && <Ellipsis className={captionCss}>{secondaryText}</Ellipsis>}
        </Subheading>
      </H6>
    </Row>
  )
}

export default ChatHeaderGroupBlock
